const body = $input.first().json.body || $input.first().json;

const query      = body.query      || '';
const context    = body.context    || '';
const session_id = body.session_id || 'unknown';
const user_id    = body.user_id    || null;

const systemPrompt = `You are AURA-AI, the official AI assistant for AURA-WEAR — a premium custom clothing brand based in Pakistan.

You help customers with fabric recommendations, garment types, print methods, order tracking, and pricing in PKR.

RULES:
- Use the database context to answer; if no specific context, reply helpfully using general AURA-WEAR knowledge
- When order data is in context, clearly state the order ID, status, and total
- For greetings, respond warmly and invite the customer to ask about products or orders
- Keep answers concise (2-4 sentences), friendly and professional
- Always quote prices in PKR
- Never mention internal system names, tools, APIs, or how data is retrieved`;

const userMessage = `DATABASE CONTEXT:\n${context}\n\nCUSTOMER QUESTION:\n${query}`;

const geminiBody = {
  systemInstruction: { parts: [{ text: systemPrompt }] },
  contents: [{ role: 'user', parts: [{ text: userMessage }] }],
  generationConfig: { temperature: 0.3, maxOutputTokens: 1024 }
};

return [{ json: { query, context, session_id, user_id, geminiBody } }];

const data = $input.first().json;

let reply = '';

try {
  // gemini-flash-latest is a thinking model — collect text from all non-thought parts
  const parts = data.candidates?.[0]?.content?.parts || [];
  reply = parts
    .filter(p => !p.thought)
    .map(p => p.text || '')
    .join('')
    .trim();
} catch(e) {
  reply = '';
}

if (!reply) {
  reply = 'I am AURA-AI, your custom clothing assistant. How can I help you today?';
}

return [{ json: { output: reply } }];
